ucs.kql:
let browsers = dynamic(["chrome.exe","msedge.exe","firefox.exe","brave.exe","opera.exe","iexplore.exe"]);
let shells = dynamic(["powershell.exe","pwsh.exe","cmd.exe","wscript.exe","mshta.exe","curl.exe","bash","zsh","sh","osascript"]);
let clickfix_keywords = dynamic(["iwr ","Invoke-WebRequest","Invoke-Expression"," IEX","curl http","curl -fsSL","wget http","FromBase64String","-enc ","-EncodedCommand"]);
let lure_keywords = dynamic(["camera","driver","captcha","verify","meeting","willo","interview","freeconference","hiring","chrome-update","runtime"]);
DeviceProcessEvents
| where Timestamp > ago(2d)
| where InitiatingProcessFileName in~ (browsers) or InitiatingProcessParentFileName in~ (browsers) or InitiatingProcessFileName in~ (dynamic(["explorer.exe","Terminal","iTerm2"]))
| where FileName in~ (shells)
| where ProcessCommandLine has_any (clickfix_keywords)
| where ProcessCommandLine has_any (lure_keywords) or ProcessCommandLine matches regex @"(?i)(python|node|\.tmp|AppData\\Local\\Temp)"
| project Timestamp, DeviceName, AccountName, InitiatingProcessFileName, FileName, ProcessCommandLine, InitiatingProcessCommandLine
| extend Actor="Contagious Interview (ClickFix variant) / Validin Jan-2025 / DEV#POPPER"
| order by Timestamp desc
